import { closeBrackets, closeBracketsKeymap } from '@codemirror/autocomplete';
import { defaultKeymap, history, redo, undo } from '@codemirror/commands';
import { syntaxHighlighting } from '@codemirror/language';
import {
  Annotation,
  Compartment,
  EditorState,
  StateEffect,
  StateField,
  type Transaction,
} from '@codemirror/state';
import { drawSelection, EditorView, keymap } from '@codemirror/view';

import { filterFieldHighlighter } from '../decorations/highlight.js';
import type { FilterFieldProps } from '../FilterField.types.js';
import { filterFieldLanguageExtension } from '../parser/filterfield-language.js';
import type { FilterFieldSuggestion } from '../suggestions/Suggestion.types.js';
import type { FilterFieldError } from '../types/filter-field-error.js';

export const placeholderCompartment = new Compartment();
export const suggestionsCompartment = new Compartment();
export const ariaAttributesCompartment = new Compartment();
export const disabledPropCompartment = new Compartment();
export const readOnlyPropCompartment = new Compartment();

export const stringAnnotation = Annotation.define<string>();

/**
 * Transaction annotation dispatched when deleting a statement using the widget.
 * @internal
 */
export const ANNOTATION_DELETE_STATEMENT = 'input.type.delete-statement';

/**
 * Transaction annotation dispatched when applying a suggestion.
 * @internal
 */
export const ANNOTATION_SUGGESTION_APPLY = 'suggestion.apply';

/**
 * Transaction annotation dispatched when pinning a suggestion.
 * @internal
 */
export const ANNOTATION_SUGGESTION_PIN = 'suggestion.pin';

/**
 * Transaction annotation dispatched to work around missing compositionend events.
 * @internal
 */
export const ANNOTATION_COMPOSE_END = 'input.type.compose.end';

/**
 * Transaction annotation dispatched for controlled value changes.
 * @internal
 */
export const ANNOTATION_DOC_CHANGED_CONTROLLED = 'doc-changed.controlled';

/**
 * Transaction annotation dispatched for stopping the pasted content insertion mode.
 * @internal
 */
export const ANNOTATION_END_PASTING_MODE = 'pasting-mode.end';

/**
 * @internal
 */
export type PastingInfo = {
  pastingInProgress: boolean;
  range?: { from: number; to: number };
  cancelPastingMode?: boolean;
};

/**
 * We need to store the pastingMode in a StateField to be able
 * to access it in the decorations.
 * @internal
 */
export const pastingEffect = StateEffect.define<PastingInfo>();

/**
 * @internal
 */
export const pastingMode = StateField.define<PastingInfo>({
  create: () => {
    return { pastingInProgress: false };
  },
  update(value: PastingInfo, transaction: Transaction) {
    for (const effect of transaction.effects) {
      if (effect.is(pastingEffect)) {
        value = effect.value;
      }
    }

    return value;
  },
});

/**
 * We need to store the validatorMap in a StateField to be able
 * to access it in the generateErrorsOrDiagnostics() function
 * @internal
 */
export const validatorMapEffect =
  StateEffect.define<FilterFieldProps['validatorMap']>();

/**
 * @internal
 */
export const usedValidatorMap = StateField.define<
  FilterFieldProps['validatorMap']
>({
  create: () => undefined,
  update(value: FilterFieldProps['validatorMap'], transaction: Transaction) {
    for (const effect of transaction.effects) {
      if (effect.is(validatorMapEffect)) {
        value = effect.value;
      }
    }

    return value;
  },
});

/**
 * State field to store the filter field errors.
 * They are generated in the tree conversion and then re-used in the plugins for
 * creating the error decorations and tooltips.
 * @internal
 */
export const errorsEffect = StateEffect.define<{
  errors: FilterFieldError[];
}>();

/**
 * @internal
 */
export const usedErrors = StateField.define<{ errors: FilterFieldError[] }>({
  create() {
    return { errors: [] };
  },
  update(value: { errors: FilterFieldError[] }, transaction: Transaction) {
    for (const effect of transaction.effects) {
      if (effect.is(errorsEffect)) {
        value.errors = [];
      }
    }

    return value;
  },
});

/**
 * List of keys that are handled separately and should not trigger the default behavior.
 * @internal
 */
export const overrideKeys = ['ArrowUp', 'ArrowDown', 'Enter', 'Mod-Enter'];

/**
 * List of static editor extensions.
 * @internal
 */
export const staticEditorExtensions = [
  /**
   * General
   */
  // Enable line wrapping so that overflowing text is wrapped into the next line.
  EditorView.lineWrapping,
  // Enable multiple selections (CMD / ctrl + drag).
  EditorState.allowMultipleSelections.of(true),
  // Provides a undo/redo history
  history(),
  // Draw custom cursor.
  drawSelection(),

  keymap.of([
    ...defaultKeymap.filter(({ key }) => !overrideKeys.includes(key ?? '')),
    ...closeBracketsKeymap,
    {
      key: 'Mod-z',
      run: undo,
    },
    {
      key: 'Mod-y',
      run: redo,
    },
    {
      key: 'Mod-Shift-z',
      run: redo,
    },
  ]),

  /**
   * Filter field language + syntax highlighting.
   *
   * Error highlighting is also done with the highlight extensions, since using an actual
   * linter, potential errors only show up after a short (configurable) delay. As soon as
   * you type something again, the errors disappear and then show up again if the input is
   * still invalid. Using the decoration plugins, we can immediately show errors.
   * The actual linter extension is only used to show tooltips with proper error messages.
   */
  // The extension for parsing the filter field language into a syntax tree.
  filterFieldLanguageExtension,
  // Automatically close brackets.
  closeBrackets(),

  // Enable highlighting using the defined highlighter.
  // This adds the spans and classes used to style the different parts of a filter.
  syntaxHighlighting(filterFieldHighlighter),
];

/**
 * Effect for updating the recent filters in the codemirror state.
 * @internal
 */
export const recentFiltersEffect =
  StateEffect.define<FilterFieldSuggestion[]>();

/**
 * Defines a codemirror state field which holds recent filters
 * @internal
 */
export const usedRecentFilters = StateField.define<FilterFieldSuggestion[]>({
  create() {
    return [];
  },
  update(value: FilterFieldSuggestion[], transaction: Transaction) {
    for (const effect of transaction.effects) {
      if (effect.is(recentFiltersEffect)) {
        value = effect.value;
      }
    }
    return value;
  },
});

/**
 * Effect for updating the pinned filters in the codemirror state.
 * @internal
 */
export const pinnedFiltersEffect =
  StateEffect.define<FilterFieldSuggestion[]>();

/**
 * Defines a codemirror state field which holds pinned filters
 * @internal
 */
export const usedPinnedFilters = StateField.define<FilterFieldSuggestion[]>({
  create() {
    return [];
  },
  update(value: FilterFieldSuggestion[], transaction: Transaction) {
    for (const effect of transaction.effects) {
      if (effect.is(pinnedFiltersEffect)) {
        value = effect.value;
      }
    }
    return value;
  },
});
